"use client";

import {
  BookOpenIcon,
  ClockIcon,
  LifeBuoyIcon,
  MessageSquareIcon,
  StarIcon,
} from "lucide-react";
import { Fragment, useState } from "react";
import { Button } from "@/registry/default/ui/button";
import {
  Command,
  CommandCollection,
  CommandDialog,
  CommandDialogPopup,
  CommandDialogTrigger,
  CommandEmpty,
  CommandGroup,
  CommandGroupLabel,
  CommandInput,
  CommandItem,
  CommandList,
  CommandPanel,
  CommandSeparator,
} from "@/registry/default/ui/command";

type Item = {
  value: string;
  label: string;
  time?: string;
  icon: "star" | "clock" | "book" | "lifebuoy" | "message";
};

type Group = { value: string; label: string; items: Item[] };

const groups: Group[] = [
  {
    value: "starred",
    label: "Starred",
    items: [
      { value: "design-system", label: "Design System", icon: "star" },
      { value: "api-documentation", label: "API Documentation", icon: "star" },
    ],
  },
  {
    value: "recent",
    label: "Recent",
    items: [
      { value: "dashboard-analytics", label: "Dashboard Analytics", icon: "clock", time: "2m ago" },
      { value: "user-settings", label: "User Settings", icon: "clock", time: "15m ago" },
      { value: "team-members", label: "Team Members", icon: "clock", time: "1h ago" },
      { value: "billing-plans", label: "Billing & Plans", icon: "clock", time: "2h ago" },
    ],
  },
  {
    value: "help",
    label: "Help",
    items: [
      { value: "documentation", label: "Documentation", icon: "book" },
      { value: "help-support", label: "Help & Support", icon: "lifebuoy" },
      { value: "contact-us", label: "Contact Us", icon: "message" },
    ],
  },
];

const icons: Record<Item["icon"], React.ReactNode> = {
  star: <StarIcon className="size-4 shrink-0 text-yellow-500" />,
  clock: <ClockIcon className="size-4 shrink-0 text-muted-foreground" />,
  book: <BookOpenIcon className="size-4 shrink-0" />,
  lifebuoy: <LifeBuoyIcon className="size-4 shrink-0" />,
  message: <MessageSquareIcon className="size-4 shrink-0" />,
};

export default function Component() {
  const [open, setOpen] = useState(false);

  return (
    <CommandDialog onOpenChange={setOpen} open={open}>
      <CommandDialogTrigger render={<Button variant="outline" />}>
        Search Everything
      </CommandDialogTrigger>
      <CommandDialogPopup>
        <Command items={groups}>
          <CommandInput placeholder="Search or jump to..." />
          <CommandPanel>
            <CommandEmpty>No results found.</CommandEmpty>
            <CommandList>
              {(group: Group, index: number) => (
                <Fragment key={group.value}>
                  {index > 0 && <CommandSeparator />}
                  <CommandGroup items={group.items}>
                    <CommandGroupLabel>{group.label}</CommandGroupLabel>
                    <CommandCollection>
                      {(item: Item) => (
                        <CommandItem
                          className="gap-2"
                          key={item.value}
                          value={item.value}
                        >
                          {icons[item.icon]}
                          <span>{item.label}</span>
                          {item.time && (
                            <div
                              className="ml-auto"
                              data-slot="command-shortcut"
                            >
                              <span>{item.time}</span>
                            </div>
                          )}
                        </CommandItem>
                      )}
                    </CommandCollection>
                  </CommandGroup>
                </Fragment>
              )}
            </CommandList>
          </CommandPanel>
        </Command>
      </CommandDialogPopup>
    </CommandDialog>
  );
}
